VALUES
  ('dietitian-moex-08654', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '植物化學成分（Phytochemicals）是指在水果、蔬菜、穀類等食物中所含的化合物，此成分對生物體含有 多種功效包括具有抗氧化、抗老化及抗癌等。下列何者不屬於Phytochemicals？', '["Flavonoids", "Diallyl Disulfide", "Squalene", "Caffeic acid"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08655', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關類固醇激素特性之敘述，何者正確？', '["在血液循環中大部分呈現游離態", "受器（receptor）位於細胞內或細胞核內", "被代謝所需的時間較胜肽類激素為短", "作用與基因轉錄無關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08656', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者可抑制泌乳激素（prolactin）的分泌？', '["體介素（somatomedin)", "催產激素（oxytocin）", "腎上腺素（epinephrine）", "多巴胺（dopamine）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08657', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在甲狀腺素存在的情況下，腎上腺素促進脂肪分解成脂肪酸的作用大增，此現象稱為甲狀腺素對於腎上 腺素的產熱作用具有：', '["向上調控（up-regulation）", "允許作用（permissive effect）", "啟動作用（priming effect）", "加乘作用（synergistic effect）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08658', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關甲狀腺素合成及分泌之敘述，何者正確？', '["碘（I）會在濾泡細胞（follicular cell）內迅速的被還原成碘離子（I－） 2", "甲狀腺素（T ，T ）的合成在濾泡細胞內完成", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08659', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '4', '["T ，T 在濾泡空腔（lumen）中與甲狀腺球蛋白（thyroglobulin）結合", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08660', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '4', '["T ，T 與甲狀腺球蛋白結合的大分子以胞吐（exocytosis）的方式被分泌至血液循環", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
