  ('dietitian-moex-08663', 'dietitian', 'dietitian-moex-098-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '暴露於高濃度激素後，常導致受器對於該激素的反應性降低，此現象稱為：', '["向上調控（up-regulation）", "向下調控（down-regulation）", "增效作用（agonist effect）", "拮抗作用（antagonist effect）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "57952c065569", "answer_pdf_sha1": "66eb9b1044c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
